export const indexHtml = "<!doctype html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"utf-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n    <title>cnproxy — traffic inspector</title>\n    <link rel=\"stylesheet\" href=\"/style.css\" />\n  </head>\n  <body>\n    <header class=\"toolbar\">\n      <div class=\"brand\"><span class=\"logo\">⚡</span> cnproxy</div>\n      <div class=\"status\" id=\"status\">connecting…</div>\n      <input id=\"filter\" class=\"filter\" placeholder=\"filter: ~m POST &amp; ~u /api  |  example.com\" spellcheck=\"false\" />\n      <div class=\"spacer\"></div>\n      <label class=\"toggle\"><input type=\"checkbox\" id=\"decrypt\" /> decrypt HTTPS</label>\n      <button id=\"composeBtn\" class=\"btn primary\">Compose</button>\n      <button id=\"rulesBtn\" class=\"btn\">Rules</button>\n      <button id=\"interceptBtn\" class=\"btn\">Intercept</button>\n      <button id=\"sessionsBtn\" class=\"btn\">Sessions</button>\n      <button id=\"workspaceBtn\" class=\"btn\">Workspace</button>\n      <button id=\"clearBtn\" class=\"btn\">Clear</button>\n      <label class=\"btn\" for=\"importHar\">Import HAR</label>\n      <input id=\"importHar\" type=\"file\" accept=\".har,application/json\" hidden />\n      <a class=\"btn\" href=\"/api/export/har\" download>Export HAR</a>\n      <a class=\"btn\" href=\"/ca.crt\" download>CA cert</a>\n    </header>\n\n    <main class=\"layout\">\n      <section class=\"list-pane\">\n        <table class=\"flow-table\">\n          <thead>\n            <tr>\n              <th class=\"c-status\">#</th>\n              <th class=\"c-method\">Method</th>\n              <th class=\"c-host\">Host</th>\n              <th class=\"c-path\">Path</th>\n              <th class=\"c-type\">Type</th>\n              <th class=\"c-size\">Size</th>\n              <th class=\"c-time\">Time</th>\n            </tr>\n          </thead>\n          <tbody id=\"rows\"></tbody>\n        </table>\n      </section>\n\n      <section class=\"detail-pane\" id=\"detail\">\n        <div class=\"empty\">Select a request to inspect it.</div>\n      </section>\n    </main>\n\n    <!-- Rules editor drawer -->\n    <div class=\"drawer\" id=\"rulesDrawer\" hidden>\n      <div class=\"drawer-head\">\n        <strong>Rules</strong>\n        <span class=\"hint\">one per line — <code>pattern operator://value</code></span>\n        <div class=\"spacer\"></div>\n        <button id=\"rulesSave\" class=\"btn primary\">Apply</button>\n        <button id=\"rulesClose\" class=\"btn\">Close</button>\n      </div>\n      <textarea id=\"rulesText\" class=\"code\" spellcheck=\"false\" placeholder=\"# examples (quote filter patterns that contain spaces)\nexample.com host://127.0.0.1\n/api/user mock://{&quot;id&quot;:1,&quot;name&quot;:&quot;mock&quot;}\n*.ads.com block://\n&quot;~u jquery&quot; resReplace://s/console.log/void 0/\napi.example.com reqHeaders://{&quot;x-debug&quot;:&quot;1&quot;}\"></textarea>\n    </div>\n\n    <!-- Intercept drawer -->\n    <div class=\"drawer small\" id=\"interceptDrawer\" hidden>\n      <div class=\"drawer-head\">\n        <strong>Intercept filter</strong>\n        <span class=\"hint\">flows matching pause for resume/kill. Empty = off.</span>\n        <div class=\"spacer\"></div>\n        <button id=\"interceptSave\" class=\"btn primary\">Apply</button>\n        <button id=\"interceptClose\" class=\"btn\">Close</button>\n      </div>\n      <input id=\"interceptText\" class=\"code\" placeholder=\"~m POST &amp; ~u /checkout\" />\n      <div class=\"drawer-head\" style=\"margin-top:8px\">\n        <span class=\"hint\">Response breakpoint — pause before relaying to the client:</span>\n      </div>\n      <input id=\"interceptResText\" class=\"code\" placeholder=\"~c 500  (empty = off)\" />\n    </div>\n\n    <!-- Sessions drawer -->\n    <div class=\"drawer small\" id=\"sessionsDrawer\" hidden>\n      <div class=\"drawer-head\">\n        <strong>Sessions</strong>\n        <span class=\"hint\">save / reload captured traffic</span>\n        <div class=\"spacer\"></div>\n        <input id=\"sessionName\" class=\"code\" style=\"width:160px\" placeholder=\"name\" />\n        <button id=\"sessionSave\" class=\"btn primary\">Save</button>\n        <button id=\"sessionsClose\" class=\"btn\">Close</button>\n      </div>\n      <div id=\"sessionList\" class=\"session-list\"></div>\n    </div>\n\n    <!-- Composer drawer (API testing) -->\n    <div class=\"drawer\" id=\"composeDrawer\" hidden>\n      <div class=\"drawer-head\">\n        <strong>Compose</strong>\n        <select id=\"cMethod\" class=\"code\">\n          <option>GET</option><option>POST</option><option>PUT</option><option>PATCH</option><option>DELETE</option><option>HEAD</option><option>OPTIONS</option>\n        </select>\n        <input id=\"cUrl\" class=\"code\" style=\"flex:1\" placeholder=\"https://api.example.com/v1/items  (supports {{env}})\" />\n        <button id=\"cSend\" class=\"btn primary\">Send</button>\n        <button id=\"composeClose\" class=\"btn\">Close</button>\n      </div>\n      <!-- Auth Helper Row -->\n      <div class=\"auth-helper-row\">\n        <label>Auth:</label>\n        <select id=\"cAuthType\" class=\"code\">\n          <option value=\"none\">None</option>\n          <option value=\"bearer\">Bearer Token</option>\n          <option value=\"basic\">Basic Auth</option>\n          <option value=\"apikey\">API Key</option>\n        </select>\n        <div id=\"authFields\" class=\"auth-fields\"></div>\n        <button id=\"cApplyAuth\" class=\"btn small primary\">Apply Auth</button>\n      </div>\n      <div class=\"compose-grid\">\n        <textarea id=\"cHeaders\" class=\"code\" spellcheck=\"false\" placeholder=\"headers, one per line:&#10;authorization: Bearer {{TOKEN}}&#10;content-type: application/json\"></textarea>\n        <textarea id=\"cBody\" class=\"code\" spellcheck=\"false\" placeholder=\"request body\"></textarea>\n      </div>\n      <div class=\"drawer-head\">\n        <input id=\"cCurl\" class=\"code\" style=\"flex:1\" placeholder=\"paste a curl command and click Import\" />\n        <button id=\"cImport\" class=\"btn\">Import cURL</button>\n        <div class=\"spacer\"></div>\n        <span id=\"cResult\" class=\"hint\"></span>\n      </div>\n    </div>\n\n    <!-- Workspace drawer (Collections + Environments) -->\n    <div class=\"drawer\" id=\"workspaceDrawer\" hidden>\n      <div class=\"drawer-head\">\n        <strong>Workspace</strong>\n        <div class=\"spacer\"></div>\n        <button id=\"workspaceClose\" class=\"btn\">Close</button>\n      </div>\n      <div class=\"workspace-layout\">\n        <div class=\"workspace-pane\">\n          <h3>Environments</h3>\n          <div class=\"env-controls\">\n            <select id=\"envSelect\" class=\"code\"></select>\n            <button id=\"envNewBtn\" class=\"btn small\">New</button>\n            <button id=\"envDelBtn\" class=\"btn small\">Delete</button>\n          </div>\n          <textarea id=\"envVariables\" class=\"code\" placeholder=\"VAR_NAME=value&#10;TOKEN=bearer-token-123\" spellcheck=\"false\" style=\"height: 120px; flex: none;\"></textarea>\n          <button id=\"envSaveBtn\" class=\"btn primary small\" style=\"margin-top: 4px; align-self: flex-end;\">Save Environment</button>\n        </div>\n        <div class=\"workspace-pane\">\n          <h3>Collections</h3>\n          <div id=\"collectionsList\" class=\"collections-list\"></div>\n          <div class=\"collections-controls\" style=\"margin-top:8px\">\n            <button id=\"cSaveToCollection\" class=\"btn small primary\">Save Composer Request</button>\n          </div>\n        </div>\n      </div>\n    </div>\n\n    <!-- Diff Modal -->\n    <div class=\"modal-overlay\" id=\"diffModal\" hidden>\n      <div class=\"modal-content\">\n        <div class=\"modal-head\">\n          <strong>⚖ Visual Flow Diff</strong>\n          <div class=\"spacer\"></div>\n          <button id=\"diffClose\" class=\"btn\">Close</button>\n        </div>\n        <div class=\"diff-selection\">\n          <select id=\"diffSelectA\" class=\"code\" style=\"flex: 1;\"></select>\n          <span style=\"color: var(--text-dim);\">vs</span>\n          <select id=\"diffSelectB\" class=\"code\" style=\"flex: 1;\"></select>\n          <button id=\"diffCompareBtn\" class=\"btn primary\">Compare</button>\n        </div>\n        <div class=\"diff-body\">\n          <div class=\"diff-column\">\n            <h4>Request Diff</h4>\n            <div id=\"diffRequest\" class=\"diff-pane-content\"></div>\n          </div>\n          <div class=\"diff-column\">\n            <h4>Response Diff</h4>\n            <div id=\"diffResponse\" class=\"diff-pane-content\"></div>\n          </div>\n        </div>\n      </div>\n    </div>\n\n    <script src=\"/app.js\"></script>\n  </body>\n</html>\n";
export const appJs = "// cnproxy inspector — vanilla JS, no build step.\n\"use strict\";\n\nconst $ = (sel) => document.querySelector(sel);\nconst rowsEl = $(\"#rows\");\nconst detailEl = $(\"#detail\");\nconst statusEl = $(\"#status\");\n\nconst isLocalServer = location.hostname === \"localhost\" || location.hostname === \"127.0.0.1\";\nconst API_BASE = isLocalServer ? \"\" : \"http://127.0.0.1:8889\";\nconst WS_BASE = isLocalServer ? `ws://${location.host}` : \"ws://127.0.0.1:8889\";\n\nif (!isLocalServer) {\n  const originalFetch = window.fetch;\n  window.fetch = function (input, init) {\n    if (typeof input === \"string\" && input.startsWith(\"/\")) {\n      input = API_BASE + input;\n    }\n    return originalFetch(input, init);\n  };\n}\n\nconst state = {\n  flows: new Map(), // id -> summary\n  order: [], // ids in arrival order\n  selected: null,\n  detail: null,\n  filter: \"\",\n  tab: \"headers\",\n};\n\n// ---------------- WebSocket stream ----------------\nlet ws;\nfunction connect() {\n  ws = new WebSocket(WS_BASE + \"/ws\");\n  ws.onopen = () => setStatus(\"live\", \"live\");\n  ws.onclose = () => {\n    setStatus(\"dead\", \"disconnected\");\n    setTimeout(connect, 1500);\n  };\n  ws.onmessage = (ev) => {\n    const msg = JSON.parse(ev.data);\n    if (msg.type === \"snapshot\") {\n      state.flows.clear();\n      state.order = [];\n      for (const f of msg.flows) addFlow(f);\n      renderList();\n    } else if (msg.type === \"add\") {\n      addFlow(msg.flow);\n      renderList();\n    } else if (msg.type === \"update\" || msg.type === \"intercept\") {\n      addFlow(msg.flow);\n      renderRow(msg.flow.id);\n      if (state.selected === msg.flow.id) loadDetail(msg.flow.id);\n    } else if (msg.type === \"clear\") {\n      state.flows.clear();\n      state.order = [];\n      renderList();\n    }\n  };\n}\nfunction setStatus(cls, text) {\n  statusEl.className = \"status \" + cls;\n  statusEl.textContent = text;\n}\nfunction addFlow(f) {\n  if (!state.flows.has(f.id)) state.order.push(f.id);\n  state.flows.set(f.id, f);\n}\n\n// ---------------- list rendering ----------------\nfunction matchesFilter(f) {\n  const q = state.filter.trim().toLowerCase();\n  if (!q) return true;\n  // lightweight client filter: match method/url/host/status; ~-prefixed → url substring\n  const hay = `${f.method} ${f.url} ${f.statusCode ?? \"\"} ${f.contentType}`.toLowerCase();\n  if (q.startsWith(\"~\")) return hay.includes(q.replace(/^~\\w+\\s*/, \"\"));\n  return q.split(/\\s+/).every((part) => hay.includes(part));\n}\n\nfunction renderList() {\n  rowsEl.innerHTML = \"\";\n  for (const id of state.order) {\n    const f = state.flows.get(id);\n    if (f && matchesFilter(f)) rowsEl.appendChild(buildRow(f));\n  }\n}\n\nfunction statusClass(code) {\n  if (code === null || code === undefined || code === 0) return \"s0\";\n  return \"s\" + String(code)[0];\n}\nfunction fmtSize(n) {\n  if (!n) return \"\";\n  if (n < 1024) return n + \" B\";\n  if (n < 1048576) return (n / 1024).toFixed(1) + \" K\";\n  return (n / 1048576).toFixed(1) + \" M\";\n}\nfunction fmtTime(ms) {\n  if (ms === null || ms === undefined) return \"\";\n  return ms < 1000 ? ms + \"ms\" : (ms / 1000).toFixed(2) + \"s\";\n}\n\nfunction buildRow(f) {\n  const tr = document.createElement(\"tr\");\n  tr.dataset.id = f.id;\n  if (f.id === state.selected) tr.classList.add(\"sel\");\n  if (f.color) tr.style.boxShadow = `inset 3px 0 0 ${f.color}`;\n  const codeTxt = f.error ? \"ERR\" : f.statusCode || \"···\";\n  const tags =\n    (f.type === \"websocket\" ? `<span class=\"tag ws\">WS ${f.wsMessages}</span>` : \"\") +\n    (f.mocked ? `<span class=\"tag mock\">mock</span>` : \"\") +\n    (f.intercepted ? `<span class=\"tag int\">paused</span>` : \"\") +\n    (f.error ? `<span class=\"tag err\">err</span>` : \"\") +\n    (f.appliedRules && f.appliedRules.length ? `<span class=\"tag rule\">rule</span>` : \"\");\n  tr.innerHTML = `\n    <td class=\"c-status\"><span class=\"code-badge ${f.error ? \"s5\" : statusClass(f.statusCode)}\">${codeTxt}</span></td>\n    <td class=\"c-method\"><span class=\"method m-${f.method}\">${f.method}</span></td>\n    <td class=\"c-host\" title=\"${esc(f.host)}\">${esc(f.host)}</td>\n    <td class=\"c-path\" title=\"${esc(f.path)}\">${esc(f.path)}${tags}</td>\n    <td class=\"c-type\">${esc(shortType(f.contentType))}</td>\n    <td class=\"c-size\">${fmtSize(f.resSize || f.reqSize)}</td>\n    <td class=\"c-time\">${fmtTime(f.duration)}</td>`;\n  tr.onclick = () => select(f.id);\n  return tr;\n}\nfunction renderRow(id) {\n  const old = rowsEl.querySelector(`tr[data-id=\"${id}\"]`);\n  const f = state.flows.get(id);\n  if (!f) return;\n  if (!matchesFilter(f)) { if (old) old.remove(); return; }\n  if (old) old.replaceWith(buildRow(f));\n}\nfunction shortType(ct) {\n  if (!ct) return \"\";\n  return ct.split(\";\")[0].replace(\"application/\", \"\").replace(\"text/\", \"\");\n}\n\n// ---------------- detail ----------------\nfunction select(id) {\n  state.selected = id;\n  document.querySelectorAll(\"tr.sel\").forEach((t) => t.classList.remove(\"sel\"));\n  const tr = rowsEl.querySelector(`tr[data-id=\"${id}\"]`);\n  if (tr) tr.classList.add(\"sel\");\n  loadDetail(id);\n}\n\nasync function loadDetail(id) {\n  const res = await fetch(`/api/flows/${id}`);\n  if (!res.ok) return;\n  state.detail = await res.json();\n  renderDetail();\n}\n\nfunction renderDetail() {\n  const d = state.detail;\n  if (!d) return;\n  const intercepted = d.intercepted;\n  detailEl.innerHTML = `\n    <div class=\"detail-head\">\n      <div><span class=\"method m-${d.method}\">${d.method}</span> <span class=\"code-badge ${d.error ? \"s5\" : statusClass(d.statusCode)}\">${d.error ? \"ERR\" : d.statusCode || \"pending\"}</span></div>\n      <div class=\"detail-url\">${esc(d.url)}</div>\n      <div class=\"detail-actions\">\n        ${intercepted ? `<button class=\"btn primary\" onclick=\"act('${d.id}','resume')\">▶ Resume</button>\n        <button class=\"btn\" onclick=\"saveEdit('${d.id}')\">✎ Apply edit</button>\n        <button class=\"btn\" onclick=\"act('${d.id}','kill')\">✖ Kill</button>` : \"\"}\n        <button class=\"btn\" onclick=\"act('${d.id}','replay')\">↻ Replay</button>\n        <button class=\"btn ${d.marked ? \"active\" : \"\"}\" onclick=\"act('${d.id}','mark')\">★ Mark</button>\n        <button class=\"btn\" onclick=\"openDiff('${d.id}')\">⚖ Diff</button>\n        <button class=\"btn\" onclick=\"editToComposer('${d.id}')\">✏ Edit & resend</button>\n        <span class=\"copyas\">\n          <button class=\"btn\">⧉ Copy as ▾</button>\n          <span class=\"copyas-menu\">\n            <a onclick=\"copyCode('${d.id}','curl')\">curl</a>\n            <a onclick=\"copyCode('${d.id}','fetch')\">fetch</a>\n            <a onclick=\"copyCode('${d.id}','python')\">python</a>\n          </span>\n        </span>\n      </div>\n    </div>\n    ${intercepted ? interceptEditor(d) : \"\"}\n    <div class=\"tabs\" id=\"tabs\">\n      ${tabBtn(\"headers\", \"Headers\")}\n      ${tabBtn(\"request\", \"Request\")}\n      ${tabBtn(\"response\", \"Response\")}\n      ${d.type === \"websocket\" ? tabBtn(\"ws\", \"WebSocket (\" + d.websocketMessages.length + \")\") : \"\"}\n    </div>\n    <div class=\"tab-body\" id=\"tabBody\"></div>`;\n  detailEl.querySelectorAll(\".tab\").forEach((t) => (t.onclick = () => { state.tab = t.dataset.tab; renderTab(); }));\n  renderTab();\n}\nfunction tabBtn(id, label) {\n  return `<div class=\"tab ${state.tab === id ? \"active\" : \"\"}\" data-tab=\"${id}\">${label}</div>`;\n}\n\nfunction renderTab() {\n  const d = state.detail;\n  const body = $(\"#tabBody\");\n  if (!body || !d) return;\n  if (state.tab === \"headers\") body.innerHTML = headersView(d);\n  else if (state.tab === \"request\") body.innerHTML = bodyView(d.request, d.method + \" \" + d.path, d, true);\n  else if (state.tab === \"response\") body.innerHTML = d.response ? bodyView(d.response, \"Status \" + d.response.statusCode, d, false) : `<div class=\"note\">No response${d.error ? \" — \" + esc(d.error) : \" yet\"}.</div>`;\n  else if (state.tab === \"ws\") body.innerHTML = wsView(d);\n}\n\nfunction headersView(d) {\n  let html = `<div class=\"section-title\">General</div><div class=\"kv\">\n    <div class=\"k\">URL</div><div class=\"v\">${esc(d.url)}</div>\n    <div class=\"k\">Method</div><div class=\"v\">${d.method}</div>\n    <div class=\"k\">Status</div><div class=\"v\">${d.statusCode ?? \"—\"} ${esc(d.response?.reason || \"\")}</div>\n    <div class=\"k\">Client</div><div class=\"v\">${esc(d.client.address)}:${d.client.port}${d.client.tls ? \" (TLS)\" : \"\"}</div>\n    <div class=\"k\">Duration</div><div class=\"v\">${fmtTime(d.duration) || \"—\"}</div>\n    ${d.appliedRules?.length ? `<div class=\"k\">Rules</div><div class=\"v\">${esc(d.appliedRules.join(\", \"))}</div>` : \"\"}\n    ${timingRow(d.timings)}\n  </div>`;\n  html += `<div class=\"section-title\">Request headers</div>${kvHeaders(d.request.headers)}`;\n  if (d.response) html += `<div class=\"section-title\">Response headers</div>${kvHeaders(d.response.headers)}`;\n  return html;\n}\nfunction kvHeaders(headers) {\n  return `<div class=\"kv\">${headers.map(([k, v]) => `<div class=\"k\">${esc(k)}</div><div class=\"v\">${esc(v)}</div>`).join(\"\")}</div>`;\n}\n\nfunction bodyView(msg, title, d, isReq) {\n  if (!msg.body) return `<div class=\"note\">No body.</div>`;\n  const bytes = b64ToBytes(msg.body);\n  const ct = headerVal(msg.headers, \"content-type\");\n  let out = \"\";\n  if (msg.bodyTruncated) out += `<div class=\"note\">body truncated for display</div>`;\n  if (/^image\\//.test(ct)) {\n    out += `<img class=\"preview\" src=\"data:${ct};base64,${msg.body}\" />`;\n    return out;\n  }\n  // Bodies are captured already-decoded (gzip/br/deflate decompressed server-side), so render text.\n  let text = new TextDecoder(\"utf-8\", { fatal: false }).decode(bytes);\n  if (/json/.test(ct)) {\n    try { text = JSON.stringify(JSON.parse(text), null, 2); } catch {}\n  }\n  out += `<pre class=\"body\">${esc(text)}</pre>`;\n  return out;\n}\n\nfunction wsView(d) {\n  const send = `<div class=\"ws-send\">\n    <input id=\"wsText\" class=\"code\" placeholder=\"message to inject\" />\n    <button class=\"btn\" onclick=\"wsSend('${d.id}', false)\">▼ to client</button>\n    <button class=\"btn\" onclick=\"wsSend('${d.id}', true)\">▲ to server</button>\n  </div>`;\n  if (!d.websocketMessages.length) return send + `<div class=\"note\">No messages captured yet.</div>`;\n  return (\n    send +\n    d.websocketMessages\n      .map((m) => {\n        const txt = m.type === \"text\" ? new TextDecoder().decode(b64ToBytes(m.content)) : `[binary ${b64ToBytes(m.content).length} bytes]`;\n        return `<div class=\"ws-msg ${m.fromClient ? \"up\" : \"down\"}\">${m.fromClient ? \"▲ \" : \"▼ \"}${esc(txt)}</div>`;\n      })\n      .join(\"\")\n  );\n}\n\nfunction timingRow(t) {\n  if (!t) return \"\";\n  const fmt = (n) => (typeof n === \"number\" ? n + \"ms\" : \"—\");\n  return `<div class=\"k\">Timing</div><div class=\"v timing\">dns ${fmt(t.dns)} · connect ${fmt(t.connect)} · tls ${fmt(t.tls)} · ttfb ${fmt(t.ttfb)}</div>`;\n}\n\nfunction interceptEditor(d) {\n  const reqHeaders = d.request.headers.map(([k, v]) => `${k}: ${v}`).join(\"\\n\");\n  const reqBody = d.request.body ? new TextDecoder().decode(b64ToBytes(d.request.body)) : \"\";\n  const resHeaders = d.response ? d.response.headers.map(([k, v]) => `${k}: ${v}`).join(\"\\n\") : \"\";\n  const resBody = d.response?.body ? new TextDecoder().decode(b64ToBytes(d.response.body)) : \"\";\n  const isResp = !!d.response;\n  return `<div class=\"editor\">\n    <div class=\"hint\">Paused — edit and Apply, then Resume.</div>\n    <label>${isResp ? \"Response\" : \"Request\"} headers</label>\n    <textarea id=\"edHeaders\" class=\"code\">${esc(isResp ? resHeaders : reqHeaders)}</textarea>\n    <label>${isResp ? \"Response\" : \"Request\"} body</label>\n    <textarea id=\"edBody\" class=\"code\">${esc(isResp ? resBody : reqBody)}</textarea>\n  </div>`;\n}\n\n// ---------------- actions ----------------\nwindow.act = async (id, action) => {\n  await fetch(`/api/flows/${id}/${action}`, { method: \"POST\" });\n  if (action === \"resume\" || action === \"kill\") {\n    // detail will refresh via ws update\n  } else {\n    loadDetail(id);\n  }\n};\n\nfunction parseHeaderLines(text) {\n  const out = [];\n  for (const line of (text || \"\").split(\"\\n\")) {\n    const idx = line.indexOf(\":\");\n    if (idx === -1) continue;\n    out.push([line.slice(0, idx).trim(), line.slice(idx + 1).trim()]);\n  }\n  return out;\n}\n\n// Apply a breakpoint edit to the paused flow (request or response, whichever is present).\nwindow.saveEdit = async (id) => {\n  const d = state.detail;\n  const headers = parseHeaderLines($(\"#edHeaders\")?.value);\n  const body = btoa(unescape(encodeURIComponent($(\"#edBody\")?.value || \"\")));\n  const patch = d.response ? { response: { headers, body } } : { request: { headers, body } };\n  await fetch(`/api/flows/${id}/edit`, { method: \"POST\", headers: { \"content-type\": \"application/json\" }, body: JSON.stringify(patch) });\n};\n\n// Copy a flow as a code snippet (curl/fetch/python).\nwindow.copyCode = async (id, lang) => {\n  const code = await (await fetch(`/api/flows/${id}/code?lang=${lang}`)).text();\n  try { await navigator.clipboard.writeText(code); } catch {}\n  flash(`copied as ${lang}`);\n};\n\n// Load a captured flow's request into the composer for editing + resend.\nwindow.editToComposer = (id) => {\n  const d = state.detail;\n  if (!d) return;\n  $(\"#cMethod\").value = d.method;\n  $(\"#cUrl\").value = d.url;\n  $(\"#cHeaders\").value = (d.request.headers || []).filter(([k]) => k.toLowerCase() !== \"host\").map(([k, v]) => `${k}: ${v}`).join(\"\\n\");\n  $(\"#cBody\").value = d.request.body ? new TextDecoder().decode(b64ToBytes(d.request.body)) : \"\";\n  drawer(\"#composeDrawer\", true);\n};\n\nwindow.wsSend = async (id, toServer) => {\n  const text = $(\"#wsText\")?.value || \"\";\n  await fetch(`/api/flows/${id}/ws-send`, { method: \"POST\", headers: { \"content-type\": \"application/json\" }, body: JSON.stringify({ text, toServer }) });\n  if ($(\"#wsText\")) $(\"#wsText\").value = \"\";\n};\n\n// ---------------- composer ----------------\n$(\"#composeBtn\").onclick = () => drawer(\"#composeDrawer\", true);\n$(\"#composeClose\").onclick = () => drawer(\"#composeDrawer\", false);\n$(\"#cImport\").onclick = async () => {\n  const command = $(\"#cCurl\").value.trim();\n  if (!command) return;\n  const spec = await (await fetch(\"/api/curl/parse\", { method: \"POST\", headers: { \"content-type\": \"application/json\" }, body: JSON.stringify({ command }) })).json();\n  $(\"#cMethod\").value = (spec.method || \"GET\").toUpperCase();\n  $(\"#cUrl\").value = spec.url || \"\";\n  $(\"#cHeaders\").value = (spec.headers || []).map(([k, v]) => `${k}: ${v}`).join(\"\\n\");\n  $(\"#cBody\").value = spec.body || \"\";\n};\n$(\"#cSend\").onclick = async () => {\n  const spec = {\n    method: $(\"#cMethod\").value,\n    url: $(\"#cUrl\").value.trim(),\n    headers: parseHeaderLines($(\"#cHeaders\").value),\n    body: $(\"#cBody\").value,\n  };\n  if (!spec.url) return;\n  $(\"#cResult\").textContent = \"sending…\";\n  try {\n    const flow = await (await fetch(\"/api/compose\", { method: \"POST\", headers: { \"content-type\": \"application/json\" }, body: JSON.stringify(spec) })).json();\n    $(\"#cResult\").textContent = `→ ${flow.error ? \"error: \" + flow.error : flow.statusCode + \" (\" + (flow.duration ?? \"?\") + \"ms)\"}`;\n    if (flow.id) select(flow.id);\n  } catch (e) {\n    $(\"#cResult\").textContent = \"failed\";\n  }\n};\n\n// ---------------- sessions ----------------\n$(\"#sessionsBtn\").onclick = async () => { drawer(\"#sessionsDrawer\", true); renderSessions(); };\n$(\"#sessionsClose\").onclick = () => drawer(\"#sessionsDrawer\", false);\n$(\"#sessionSave\").onclick = async () => {\n  const name = $(\"#sessionName\").value.trim() || \"session\";\n  await fetch(\"/api/sessions/save\", { method: \"POST\", headers: { \"content-type\": \"application/json\" }, body: JSON.stringify({ name }) });\n  renderSessions();\n  flash(\"saved \" + name);\n};\nasync function renderSessions() {\n  const list = await (await fetch(\"/api/sessions\")).json();\n  $(\"#sessionList\").innerHTML = list.length\n    ? list.map((s) => `<div class=\"session-row\"><span>${esc(s.name)} <em>(${s.flows} flows)</em></span><button class=\"btn\" onclick=\"loadSession('${esc(s.name)}')\">Load</button></div>`).join(\"\")\n    : `<div class=\"note\">No saved sessions.</div>`;\n}\nwindow.loadSession = async (name) => {\n  await fetch(\"/api/sessions/load\", { method: \"POST\", headers: { \"content-type\": \"application/json\" }, body: JSON.stringify({ name }) });\n  flash(\"loaded \" + name);\n};\n\n// ---------------- HAR import ----------------\n$(\"#importHar\").onchange = async (e) => {\n  const file = e.target.files?.[0];\n  if (!file) return;\n  const text = await file.text();\n  try {\n    const har = JSON.parse(text);\n    const r = await (await fetch(\"/api/import/har\", { method: \"POST\", headers: { \"content-type\": \"application/json\" }, body: JSON.stringify(har) })).json();\n    flash(`imported ${r.flows} flows`);\n  } catch {\n    flash(\"invalid HAR\");\n  }\n  e.target.value = \"\";\n};\n\nfunction flash(msg) {\n  const el = $(\"#status\");\n  const prev = el.textContent;\n  el.textContent = msg;\n  setTimeout(() => (el.textContent = prev), 1500);\n}\n\n// ---------------- options / drawers ----------------\nasync function loadOptions() {\n  const o = await (await fetch(\"/api/options\")).json();\n  $(\"#decrypt\").checked = !!o.decryptHttps;\n  $(\"#rulesText\").value = o.rules || \"\";\n  $(\"#interceptText\").value = o.intercept || \"\";\n  if ($(\"#interceptResText\")) $(\"#interceptResText\").value = o.interceptResponse || \"\";\n  $(\"#interceptBtn\").classList.toggle(\"active\", !!o.intercept || !!o.interceptResponse);\n}\nasync function patchOptions(patch) {\n  await fetch(\"/api/options\", { method: \"POST\", headers: { \"content-type\": \"application/json\" }, body: JSON.stringify(patch) });\n}\n\n$(\"#decrypt\").onchange = (e) => patchOptions({ decryptHttps: e.target.checked });\n$(\"#clearBtn\").onclick = () => fetch(\"/api/clear\", { method: \"POST\" });\n$(\"#filter\").oninput = (e) => { state.filter = e.target.value; renderList(); };\n\nfunction drawer(id, open) { $(id).hidden = !open; }\n$(\"#rulesBtn\").onclick = () => drawer(\"#rulesDrawer\", true);\n$(\"#rulesClose\").onclick = () => drawer(\"#rulesDrawer\", false);\n$(\"#rulesSave\").onclick = async () => { await patchOptions({ rules: $(\"#rulesText\").value }); drawer(\"#rulesDrawer\", false); };\n$(\"#interceptBtn\").onclick = () => drawer(\"#interceptDrawer\", true);\n$(\"#interceptClose\").onclick = () => drawer(\"#interceptDrawer\", false);\n$(\"#interceptSave\").onclick = async () => {\n  const reqExpr = $(\"#interceptText\").value;\n  const resExpr = $(\"#interceptResText\") ? $(\"#interceptResText\").value : \"\";\n  await patchOptions({ intercept: reqExpr, interceptResponse: resExpr });\n  $(\"#interceptBtn\").classList.toggle(\"active\", !!reqExpr || !!resExpr);\n  drawer(\"#interceptDrawer\", false);\n};\n\n// ---------------- utils ----------------\nfunction esc(s) {\n  return String(s ?? \"\").replace(/[&<>\"]/g, (c) => ({ \"&\": \"&amp;\", \"<\": \"&lt;\", \">\": \"&gt;\", '\"': \"&quot;\" }[c]));\n}\nfunction headerVal(headers, name) {\n  const f = headers.find(([k]) => k.toLowerCase() === name);\n  return f ? f[1] : \"\";\n}\nfunction b64ToBytes(b64) {\n  const bin = atob(b64);\n  const arr = new Uint8Array(bin.length);\n  for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);\n  return arr;\n}\n\n// ---------------- diff modal ----------------\nwindow.openDiff = (id) => {\n  $(\"#diffModal\").hidden = false;\n  const flows = Array.from(state.flows.values());\n  let options = \"\";\n  for (const f of flows) {\n    options += `<option value=\"${f.id}\" ${f.id === id ? \"selected\" : \"\"}>${esc(f.method)} ${esc(f.path)} (${f.id.slice(0, 8)})</option>`;\n  }\n  $(\"#diffSelectA\").innerHTML = options;\n  $(\"#diffSelectB\").innerHTML = options;\n  if (flows.length > 1) {\n    const other = flows.find(f => f.id !== id);\n    if (other) {\n      $(\"#diffSelectB\").value = other.id;\n    }\n  }\n  triggerDiffCompare();\n};\n\nasync function triggerDiffCompare() {\n  const idA = $(\"#diffSelectA\").value;\n  const idB = $(\"#diffSelectB\").value;\n  if (!idA || !idB) return;\n\n  $(\"#diffRequest\").innerHTML = \"Loading diff...\";\n  $(\"#diffResponse\").innerHTML = \"Loading diff...\";\n\n  try {\n    const res = await fetch(`/api/diff?a=${idA}&b=${idB}`);\n    if (!res.ok) throw new Error(\"Diff failed\");\n    const diff = await res.json();\n\n    const renderLines = (lines) => {\n      if (!lines || !lines.length) return `<div class=\"note\">No content or identical.</div>`;\n      return lines.map(line => `<span class=\"diff-line ${line.op}\">${esc(line.text || \" \")}</span>`).join(\"\");\n    };\n\n    $(\"#diffRequest\").innerHTML = renderLines(diff.request);\n    $(\"#diffResponse\").innerHTML = renderLines(diff.response);\n  } catch (e) {\n    $(\"#diffRequest\").innerHTML = \"Error loading diff.\";\n    $(\"#diffResponse\").innerHTML = \"Error loading diff.\";\n  }\n}\n\n$(\"#diffClose\").onclick = () => $(\"#diffModal\").hidden = true;\n$(\"#diffCompareBtn\").onclick = () => triggerDiffCompare();\n\n// ---------------- workspace ----------------\nstate.workspace = { collections: [], environments: [], activeEnv: null };\n\nasync function loadWorkspace() {\n  try {\n    const res = await fetch(\"/api/workspace\");\n    if (res.ok) {\n      state.workspace = await res.json();\n      renderWorkspace();\n    }\n  } catch {}\n}\n\nasync function saveWorkspace() {\n  await fetch(\"/api/workspace\", {\n    method: \"PUT\",\n    headers: { \"content-type\": \"application/json\" },\n    body: JSON.stringify(state.workspace)\n  });\n}\n\nfunction renderWorkspace() {\n  // Environments dropdown\n  const envs = state.workspace.environments || [];\n  let html = `<option value=\"\">No Active Environment</option>`;\n  for (const env of envs) {\n    html += `<option value=\"${esc(env.name)}\" ${state.workspace.activeEnv === env.name ? \"selected\" : \"\"}>${esc(env.name)}</option>`;\n  }\n  $(\"#envSelect\").innerHTML = html;\n\n  // Active environment variables text\n  const active = envs.find(e => e.name === state.workspace.activeEnv);\n  if (active) {\n    const lines = [];\n    for (const [k, v] of Object.entries(active.variables || {})) {\n      lines.push(`${k}=${v}`);\n    }\n    $(\"#envVariables\").value = lines.join(\"\\n\");\n    $(\"#envVariables\").disabled = false;\n  } else {\n    $(\"#envVariables\").value = \"\";\n    $(\"#envVariables\").disabled = true;\n  }\n\n  // Collections list\n  const cols = state.workspace.collections || [];\n  $(\"#collectionsList\").innerHTML = cols.length\n    ? cols.map((c, idx) => `\n        <div class=\"collection-item\" onclick=\"loadCollectionItem(${idx})\">\n          <span>\n            <span class=\"c-method-tag m-${c.method}\">${c.method}</span>\n            <span style=\"font-family: var(--mono);\">${esc(c.url.split(\"?\")[0])}</span>\n          </span>\n          <button class=\"c-del\" onclick=\"event.stopPropagation(); deleteCollectionItem(${idx})\">✖</button>\n        </div>`).join(\"\")\n    : `<div class=\"note\">No saved requests in collection.</div>`;\n}\n\n$(\"#workspaceBtn\").onclick = () => {\n  drawer(\"#workspaceDrawer\", true);\n  loadWorkspace();\n};\n$(\"#workspaceClose\").onclick = () => drawer(\"#workspaceDrawer\", false);\n\n$(\"#envSelect\").onchange = (e) => {\n  state.workspace.activeEnv = e.target.value || null;\n  saveWorkspace();\n  renderWorkspace();\n};\n\n$(\"#envNewBtn\").onclick = () => {\n  const name = prompt(\"Enter new environment name:\");\n  if (!name) return;\n  state.workspace.environments = state.workspace.environments || [];\n  if (state.workspace.environments.some(e => e.name === name)) return alert(\"Environment already exists.\");\n  state.workspace.environments.push({ name, variables: {} });\n  state.workspace.activeEnv = name;\n  saveWorkspace();\n  renderWorkspace();\n};\n\n$(\"#envDelBtn\").onclick = () => {\n  const active = state.workspace.activeEnv;\n  if (!active) return;\n  state.workspace.environments = state.workspace.environments.filter(e => e.name !== active);\n  state.workspace.activeEnv = null;\n  saveWorkspace();\n  renderWorkspace();\n};\n\n$(\"#envSaveBtn\").onclick = () => {\n  const activeName = state.workspace.activeEnv;\n  if (!activeName) return;\n  const active = state.workspace.environments.find(e => e.name === activeName);\n  if (!active) return;\n\n  const vars = {};\n  const text = $(\"#envVariables\").value;\n  for (const line of text.split(\"\\n\")) {\n    const trimmed = line.trim();\n    if (!trimmed || trimmed.startsWith(\"#\")) continue;\n    const eq = trimmed.indexOf(\"=\");\n    if (eq !== -1) {\n      vars[trimmed.slice(0, eq).trim()] = trimmed.slice(eq + 1).trim();\n    }\n  }\n  active.variables = vars;\n  saveWorkspace();\n  flash(\"Environment saved\");\n};\n\nwindow.loadCollectionItem = (idx) => {\n  const c = state.workspace.collections[idx];\n  if (!c) return;\n  $(\"#cMethod\").value = c.method;\n  $(\"#cUrl\").value = c.url;\n  $(\"#cHeaders\").value = c.headers.map(([k, v]) => `${k}: ${v}`).join(\"\\n\");\n  $(\"#cBody\").value = c.body || \"\";\n  drawer(\"#composeDrawer\", true);\n  drawer(\"#workspaceDrawer\", false);\n};\n\nwindow.deleteCollectionItem = (idx) => {\n  state.workspace.collections.splice(idx, 1);\n  saveWorkspace();\n  renderWorkspace();\n};\n\n$(\"#cSaveToCollection\").onclick = () => {\n  const spec = {\n    method: $(\"#cMethod\").value,\n    url: $(\"#cUrl\").value.trim(),\n    headers: parseHeaderLines($(\"#cHeaders\").value),\n    body: $(\"#cBody\").value,\n  };\n  if (!spec.url) return alert(\"Enter a URL first.\");\n  state.workspace.collections = state.workspace.collections || [];\n  state.workspace.collections.push(spec);\n  saveWorkspace();\n  flash(\"Composer saved to collections\");\n};\n\n// ---------------- auth helper ----------------\n$(\"#cAuthType\").onchange = (e) => {\n  const type = e.target.value;\n  const fields = $(\"#authFields\");\n  if (type === \"none\") {\n    fields.innerHTML = \"\";\n  } else if (type === \"bearer\") {\n    fields.innerHTML = `<input id=\"authBearerToken\" placeholder=\"Token\" class=\"code\" />`;\n  } else if (type === \"basic\") {\n    fields.innerHTML = `\n      <input id=\"authBasicUser\" placeholder=\"Username\" class=\"code\" style=\"width: 80px;\" />\n      <input id=\"authBasicPass\" placeholder=\"Password\" type=\"password\" class=\"code\" style=\"width: 80px;\" />`;\n  } else if (type === \"apikey\") {\n    fields.innerHTML = `\n      <input id=\"authApiKeyName\" placeholder=\"Header name (e.g. x-api-key)\" class=\"code\" />\n      <input id=\"authApiKeyValue\" placeholder=\"Value\" class=\"code\" />`;\n  }\n};\n\n$(\"#cApplyAuth\").onclick = () => {\n  const type = $(\"#cAuthType\").value;\n  let authName = \"\";\n  let authVal = \"\";\n\n  if (type === \"bearer\") {\n    const token = $(\"#authBearerToken\")?.value.trim();\n    if (!token) return alert(\"Bearer token required.\");\n    authName = \"authorization\";\n    authVal = `Bearer ${token}`;\n  } else if (type === \"basic\") {\n    const user = $(\"#authBasicUser\")?.value.trim() || \"\";\n    const pass = $(\"#authBasicPass\")?.value.trim() || \"\";\n    authName = \"authorization\";\n    authVal = `Basic ${btoa(unescape(encodeURIComponent(user + \":\" + pass)))}`;\n  } else if (type === \"apikey\") {\n    const name = $(\"#authApiKeyName\")?.value.trim();\n    const val = $(\"#authApiKeyValue\")?.value.trim() || \"\";\n    if (!name) return alert(\"Header name required.\");\n    authName = name.toLowerCase();\n    authVal = val;\n  }\n\n  // Inject or update the header in the textarea\n  const headers = parseHeaderLines($(\"#cHeaders\").value);\n  const filtered = headers.filter(([k]) => k.toLowerCase() !== authName);\n  if (type !== \"none\") {\n    filtered.push([authName, authVal]);\n  }\n  $(\"#cHeaders\").value = filtered.map(([k, v]) => `${k}: ${v}`).join(\"\\n\");\n  flash(\"Auth headers applied\");\n};\n\n// Initial load\nloadWorkspace();\nloadOptions();\nconnect();\n";
export const styleCss = ":root {\n  --bg: #0e1116;\n  --bg-soft: #161b22;\n  --bg-row: #11161d;\n  --bg-hover: #1c2530;\n  --bg-sel: #1f6feb33;\n  --border: #232a33;\n  --text: #d7dde5;\n  --text-dim: #8b96a5;\n  --accent: #4ea1ff;\n  --green: #3fb950;\n  --yellow: #d29922;\n  --red: #f85149;\n  --purple: #bc8cff;\n  --mono: ui-monospace, SFMono-Regular, \"SF Mono\", Menlo, Consolas, monospace;\n}\n\n* { box-sizing: border-box; }\n[hidden] { display: none !important; }\nhtml, body { height: 100%; margin: 0; }\nbody {\n  background: var(--bg);\n  color: var(--text);\n  font: 13px/1.5 -apple-system, BlinkMacSystemFont, \"Segoe UI\", Roboto, sans-serif;\n  display: flex;\n  flex-direction: column;\n  overflow: hidden;\n}\n\n/* ---- toolbar ---- */\n.toolbar {\n  display: flex;\n  align-items: center;\n  gap: 10px;\n  padding: 8px 12px;\n  background: var(--bg-soft);\n  border-bottom: 1px solid var(--border);\n  flex: 0 0 auto;\n}\n.brand { font-weight: 700; letter-spacing: .3px; }\n.logo { color: var(--yellow); }\n.status { color: var(--text-dim); font-size: 12px; min-width: 92px; }\n.status.live::before { content: \"● \"; color: var(--green); }\n.status.dead::before { content: \"● \"; color: var(--red); }\n.filter {\n  flex: 1 1 360px;\n  max-width: 520px;\n  background: var(--bg);\n  border: 1px solid var(--border);\n  color: var(--text);\n  border-radius: 6px;\n  padding: 6px 10px;\n  font-family: var(--mono);\n  font-size: 12px;\n}\n.filter:focus { outline: none; border-color: var(--accent); }\n.spacer { flex: 1; }\n.toggle { color: var(--text-dim); font-size: 12px; user-select: none; display: flex; align-items: center; gap: 4px; }\n.btn {\n  background: var(--bg);\n  border: 1px solid var(--border);\n  color: var(--text);\n  border-radius: 6px;\n  padding: 6px 12px;\n  cursor: pointer;\n  font-size: 12px;\n  text-decoration: none;\n  display: inline-block;\n}\n.btn:hover { background: var(--bg-hover); }\n.btn.primary { background: var(--accent); border-color: var(--accent); color: #051018; font-weight: 600; }\n.btn.active { border-color: var(--accent); color: var(--accent); }\n\n/* ---- layout ---- */\n.layout { flex: 1; display: flex; min-height: 0; }\n.list-pane { flex: 1 1 55%; overflow: auto; border-right: 1px solid var(--border); }\n.detail-pane { flex: 1 1 45%; overflow: auto; display: flex; flex-direction: column; }\n\n/* ---- flow table ---- */\n.flow-table { width: 100%; border-collapse: collapse; font-size: 12px; }\n.flow-table thead th {\n  position: sticky; top: 0; z-index: 1;\n  background: var(--bg-soft);\n  text-align: left;\n  padding: 6px 8px;\n  color: var(--text-dim);\n  font-weight: 600;\n  border-bottom: 1px solid var(--border);\n  white-space: nowrap;\n}\n.flow-table td { padding: 4px 8px; border-bottom: 1px solid var(--bg-row); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; max-width: 0; }\n.flow-table tbody tr { cursor: pointer; }\n.flow-table tbody tr:nth-child(odd) { background: var(--bg-row); }\n.flow-table tbody tr:hover { background: var(--bg-hover); }\n.flow-table tbody tr.sel { background: var(--bg-sel); }\n.c-status { width: 54px; }\n.c-method { width: 64px; }\n.c-host { width: 22%; }\n.c-type { width: 110px; }\n.c-size { width: 72px; text-align: right; }\n.c-time { width: 70px; text-align: right; }\n.c-size, .c-time { font-variant-numeric: tabular-nums; color: var(--text-dim); }\n\n.method { font-family: var(--mono); font-weight: 600; }\n.m-GET { color: var(--green); }\n.m-POST { color: var(--yellow); }\n.m-PUT, .m-PATCH { color: var(--purple); }\n.m-DELETE { color: var(--red); }\n\n.code-badge { font-family: var(--mono); font-weight: 600; padding: 0 4px; border-radius: 4px; }\n.s2 { color: var(--green); }\n.s3 { color: var(--accent); }\n.s4 { color: var(--yellow); }\n.s5 { color: var(--red); }\n.s0 { color: var(--text-dim); }\n.pending { color: var(--text-dim); }\n\n.tag { font-size: 10px; padding: 0 4px; border-radius: 3px; margin-left: 4px; }\n.tag.ws { background: #bc8cff33; color: var(--purple); }\n.tag.mock { background: #d2992233; color: var(--yellow); }\n.tag.rule { background: #4ea1ff33; color: var(--accent); }\n.tag.int { background: #f8514933; color: var(--red); }\n.tag.err { background: #f8514933; color: var(--red); }\n\n/* ---- detail ---- */\n.empty { margin: auto; color: var(--text-dim); }\n.detail-head { padding: 10px 12px; border-bottom: 1px solid var(--border); background: var(--bg-soft); }\n.detail-url { font-family: var(--mono); font-size: 12px; word-break: break-all; }\n.detail-actions { margin-top: 8px; display: flex; gap: 6px; flex-wrap: wrap; }\n.tabs { display: flex; gap: 2px; padding: 0 8px; border-bottom: 1px solid var(--border); background: var(--bg-soft); }\n.tab { padding: 8px 12px; cursor: pointer; color: var(--text-dim); border-bottom: 2px solid transparent; font-size: 12px; }\n.tab.active { color: var(--text); border-bottom-color: var(--accent); }\n.tab-body { padding: 12px; overflow: auto; flex: 1; }\n.kv { display: grid; grid-template-columns: max-content 1fr; gap: 2px 14px; font-family: var(--mono); font-size: 12px; }\n.kv .k { color: var(--accent); white-space: nowrap; }\n.kv .v { color: var(--text); word-break: break-all; }\n.section-title { color: var(--text-dim); text-transform: uppercase; font-size: 10px; letter-spacing: .5px; margin: 14px 0 6px; }\npre.body { background: var(--bg-soft); border: 1px solid var(--border); border-radius: 6px; padding: 10px; overflow: auto; font-family: var(--mono); font-size: 12px; white-space: pre-wrap; word-break: break-word; max-height: 60vh; }\n.note { color: var(--text-dim); font-style: italic; }\nimg.preview { max-width: 100%; border: 1px solid var(--border); border-radius: 6px; }\n.ws-msg { font-family: var(--mono); font-size: 12px; padding: 6px 8px; border-radius: 6px; margin-bottom: 4px; white-space: pre-wrap; word-break: break-word; }\n.ws-msg.up { background: #4ea1ff1a; border-left: 2px solid var(--accent); }\n.ws-msg.down { background: #3fb9501a; border-left: 2px solid var(--green); }\n\n/* ---- drawers ---- */\n.drawer {\n  position: fixed; right: 0; bottom: 0; top: 49px;\n  width: 460px; max-width: 92vw;\n  background: var(--bg-soft);\n  border-left: 1px solid var(--border);\n  display: flex; flex-direction: column;\n  box-shadow: -8px 0 24px #0008;\n  z-index: 10;\n}\n.drawer.small { top: auto; height: 130px; width: 520px; }\n.drawer-head { display: flex; align-items: center; gap: 8px; padding: 10px 12px; border-bottom: 1px solid var(--border); }\n.drawer-head .hint { color: var(--text-dim); font-size: 11px; }\n.drawer .code { flex: 1; margin: 10px; background: var(--bg); border: 1px solid var(--border); color: var(--text); border-radius: 6px; padding: 10px; font-family: var(--mono); font-size: 12px; resize: none; }\ninput.code { flex: 0 0 auto; }\ncode { background: var(--bg); padding: 1px 4px; border-radius: 3px; font-family: var(--mono); }\n\n/* ---- composer / sessions / editor / copy-as / timing (added: UI productization) ---- */\n.drawer.wide { width: 640px; }\n.compose-grid { display: grid; grid-template-rows: 1fr 1fr; flex: 1; }\n.compose-grid .code { margin: 8px 10px; min-height: 80px; }\n#composeDrawer { width: 640px; }\n.session-list { overflow: auto; padding: 6px 12px; }\n.session-row { display: flex; align-items: center; justify-content: space-between; padding: 6px 0; border-bottom: 1px solid var(--border); font-size: 12px; }\n.session-row em { color: var(--text-dim); font-style: normal; }\n.editor { padding: 8px 12px; border-bottom: 1px solid var(--border); background: #1c253033; }\n.editor label { display: block; font-size: 10px; text-transform: uppercase; color: var(--text-dim); margin: 6px 0 2px; }\n.editor .code { width: 100%; box-sizing: border-box; background: var(--bg); border: 1px solid var(--border); color: var(--text); border-radius: 6px; padding: 6px; font-family: var(--mono); font-size: 12px; min-height: 48px; resize: vertical; }\n.ws-send { display: flex; gap: 6px; margin-bottom: 8px; }\n.ws-send .code { flex: 1; background: var(--bg); border: 1px solid var(--border); color: var(--text); border-radius: 6px; padding: 6px; }\n.v.timing { font-family: var(--mono); color: var(--text-dim); }\n.copyas { position: relative; display: inline-block; }\n.copyas-menu { display: none; position: absolute; top: 100%; left: 0; background: var(--bg-soft); border: 1px solid var(--border); border-radius: 6px; z-index: 20; min-width: 90px; }\n.copyas:hover .copyas-menu { display: block; }\n.copyas-menu a { display: block; padding: 6px 12px; font-size: 12px; cursor: pointer; }\n.copyas-menu a:hover { background: var(--bg-hover); }\n\n/* ---- responsive: usable from a phone/tablet browser (mobile via proxy-config) ---- */\n@media (max-width: 760px) {\n  .toolbar { flex-wrap: wrap; height: auto; padding: 6px 8px; gap: 6px; }\n  .toolbar .filter { order: 10; flex-basis: 100%; }\n  .toolbar .spacer { display: none; }\n  .layout { flex-direction: column; }\n  .list-pane { flex: 1 1 45%; border-right: none; border-bottom: 1px solid var(--border); }\n  .detail-pane { flex: 1 1 55%; }\n  .drawer, .drawer.small, #composeDrawer { top: auto; bottom: 0; left: 0; right: 0; width: 100%; max-width: 100%; height: 70vh; }\n  .compose-grid { grid-template-rows: 1fr 1fr; }\n  /* drop lower-value columns on small screens */\n  .c-type, .c-size { display: none; }\n}\n\n/* ---- diff modal ---- */\n.modal-overlay {\n  position: fixed; top: 0; left: 0; right: 0; bottom: 0;\n  background: rgba(0, 0, 0, 0.85);\n  display: flex; align-items: center; justify-content: center;\n  z-index: 100;\n}\n.modal-content {\n  background: var(--bg-soft);\n  border: 1px solid var(--border);\n  border-radius: 12px;\n  width: 90vw; height: 90vh;\n  display: flex; flex-direction: column;\n  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.6);\n}\n.modal-head {\n  display: flex; align-items: center; padding: 12px 16px;\n  border-bottom: 1px solid var(--border);\n  background: var(--bg-soft);\n}\n.diff-selection {\n  display: flex; align-items: center; gap: 8px; padding: 10px 16px;\n  background: var(--bg-row); border-bottom: 1px solid var(--border);\n}\n.diff-body {\n  flex: 1; display: flex; min-height: 0;\n}\n.diff-column {\n  flex: 1; display: flex; flex-direction: column; overflow: hidden;\n  border-right: 1px solid var(--border);\n}\n.diff-column:last-child { border-right: none; }\n.diff-column h4 { margin: 8px 16px; color: var(--accent); font-size: 13px; }\n.diff-pane-content {\n  flex: 1; overflow: auto; padding: 10px; font-family: var(--mono); font-size: 11px; white-space: pre-wrap; line-height: 1.4; background: var(--bg);\n}\n.diff-line { display: block; padding: 2px 4px; border-radius: 3px; }\n.diff-line.del { background: rgba(248, 81, 73, 0.18); color: #ff7b72; text-decoration: line-through; }\n.diff-line.add { background: rgba(63, 185, 80, 0.18); color: #7ee787; }\n.diff-line.same { color: var(--text-dim); }\n\n/* ---- workspace ---- */\n#workspaceDrawer { width: 680px; }\n.workspace-layout {\n  display: flex; flex: 1; min-height: 0; padding: 12px; gap: 12px;\n}\n.workspace-pane {\n  flex: 1; display: flex; flex-direction: column;\n  border: 1px solid var(--border); border-radius: 8px; padding: 12px; background: var(--bg);\n}\n.workspace-pane h3 { margin: 0 0 10px; font-size: 13px; color: var(--accent); border-bottom: 1px solid var(--border); padding-bottom: 6px; }\n.env-controls { display: flex; gap: 6px; margin-bottom: 10px; }\n.env-controls select { flex: 1; background: var(--bg-soft); border: 1px solid var(--border); color: var(--text); padding: 4px 6px; border-radius: 4px; font-family: var(--mono); }\n.workspace-pane textarea.code { margin: 0; flex: 1; background: var(--bg-soft); }\n.collections-list { flex: 1; overflow: auto; }\n.collection-item {\n  display: flex; align-items: center; justify-content: space-between;\n  padding: 8px; border-bottom: 1px solid var(--border); font-size: 12px; cursor: pointer; border-radius: 6px;\n}\n.collection-item:hover { background: var(--bg-hover); }\n.collection-item .c-del { color: var(--red); font-size: 11px; font-weight: bold; border: none; background: transparent; cursor: pointer; padding: 2px 6px; }\n.collection-item .c-method-tag { font-family: var(--mono); font-weight: bold; font-size: 10px; padding: 2px 4px; border-radius: 3px; margin-right: 6px; }\n\n/* ---- auth helper ---- */\n.auth-helper-row {\n  display: flex; align-items: center; gap: 8px; padding: 8px 12px;\n  background: var(--bg-row); border-bottom: 1px solid var(--border);\n  flex-wrap: wrap;\n}\n.auth-helper-row label { font-size: 11px; color: var(--text-dim); }\n.auth-helper-row select { background: var(--bg); border: 1px solid var(--border); color: var(--text); padding: 4px 6px; border-radius: 4px; font-family: var(--mono); }\n.auth-fields { display: flex; align-items: center; gap: 6px; flex: 1; min-width: 180px; }\n.auth-fields input { background: var(--bg); border: 1px solid var(--border); color: var(--text); border-radius: 4px; padding: 4px 8px; font-size: 11px; flex: 1; font-family: var(--mono); }\n\n";
